/// Write Trinity status to /dev/shm for the observer.
///
/// Format: "saios-trinity-{trinity_id}" containing:
///   alive M_id F_id C_id integrity_n integrity_d torsion_n torsion_d coherence_n coherence_d
pub fn write_shm_status(trinity: &Trinity) -> std::io::Result<()> {
    use std::io::Write;

    let alive_flag: u8 = if trinity.alive { 1 } else { 0 };
    let m_id = trinity.vertices[0].entity_id;
    let f_id = trinity.vertices[1].entity_id;
    let c_id = trinity.vertices[2].entity_id;
    let in_ = trinity.field.integrity.numer();
    let id_ = trinity.field.integrity.denom();
    let tn = trinity.field.internal_torsion.numer();
    let td = trinity.field.internal_torsion.denom();
    let cn = trinity.shared_coherence.numer();
    let cd = trinity.shared_coherence.denom();

    let path = format!("/dev/shm/saios-trinity-{}", trinity.trinity_id);
    let mut f = std::fs::File::create(&path)?;
    write!(
        f, "{} {} {} {} {} {} {} {} {} {}",
        alive_flag, m_id, f_id, c_id, in_, id_, tn, td, cn, cd
    )?;
    Ok(())
}

